593	/// @brief Define a detector over one or more measurement results.
594	///
595	/// A detector is a parity constraint: under noise-free execution the XOR of
596	/// the referenced measurements is deterministic. Each argument is either an
597	/// individual `cudaq::measure_result` or a
598	/// `std::vector<cudaq::measure_result>`, or any combination.
599	template <typename... MeasArgs>
600	  requires(sizeof...(MeasArgs) >= 1) &&
601	          (detail::any_measure_result_or_vec<MeasArgs> && ...)
602	void detector(MeasArgs &&...ms) {
603	  ((void)ms, ...);
604	  throw std::runtime_error(detail::kQpuOnlyHostScopeError);
605	}
