607	/// @brief Define a logical observable over one or more measurement results.
608	///
609	/// A logical observable is a binary sum of measurement results that equals
610	/// the outcome of measuring a logical operator. Each argument is either an
611	/// individual `cudaq::measure_result` or a
612	/// `std::vector<cudaq::measure_result>`, or any combination. Codes
613	/// with `k` logical qubits should pair a single
614	/// `std::vector<cudaq::measure_result>` with an explicit `observable_index`
615	/// for each observable `0..k-1` (see the `(vector, std::size_t)` overload).
616	template <typename... MeasArgs>
617	  requires(sizeof...(MeasArgs) >= 1) &&
618	          (detail::any_measure_result_or_vec<MeasArgs> && ...)
619	void logical_observable(MeasArgs &&...ms) {
620	  ((void)ms, ...);
621	  throw std::runtime_error(detail::kQpuOnlyHostScopeError);
622	}
