796	/// @brief Map provided qubit arguments to a vector of QuditInfo.
797	template <typename... QuantumT>
798	void qubitsToQuditInfos(const std::tuple<QuantumT...> &quantumTuple,
799	                        std::vector<QuditInfo> &qubits) {
800	  cudaq::tuple_for_each(quantumTuple, [&](auto &&element) {
801	    using T = decltype(element);
802	    if constexpr (IsQubitType<T>::value) {
803	      qubits.push_back(qubitToQuditInfo(element));
804	    } else if constexpr (IsQvectorType<T>::value || IsQviewType<T>::value ||
805	                         IsQarrayType<T>::value) {
806	      for (auto &q : element)
807	        qubits.push_back(qubitToQuditInfo(q));
808	    }
809	  });
810	}
811	
812	/// @brief Search through the qubit arguments and see which ones are negated.
813	template <typename... QuantumT>
814	void findQubitNegations(const std::tuple<QuantumT...> &quantumTuple,
815	                        std::vector<bool> &qubitIsNegated) {
816	  cudaq::tuple_for_each(quantumTuple, [&](auto &&element) {
817	    using T = decltype(element);
818	    if constexpr (IsQubitType<T>::value) {
819	      qubitIsNegated.push_back(element.is_negative());
820	    } else if constexpr (IsQvectorType<T>::value || IsQviewType<T>::value ||
821	                         IsQarrayType<T>::value) {
822	      for (auto &q : element)
823	        qubitIsNegated.push_back(q.is_negative());
824	    }
825	    return;
826	  });
827	}
828	
829	// 1. Type traits for container detection
830	template <typename T>
831	struct is_fixed_size_container : std::false_type {};
832	
833	template <>
834	struct is_fixed_size_container<cudaq::qarray_base> : std::true_type {};
835	
836	// 2. Compile-time qubit counting logic
837	template <typename T>
838	constexpr std::size_t count_qubits_compile_time() {
839	  if constexpr (detail::IsQubitType<T>::value) {
840	    return 1;
841	  } else if constexpr (detail::IsQarrayType<T>::value) {
842	    return std::tuple_size<std::decay_t<T>>::value;
843	  } else {
844	    return 0; // Dynamic containers handled at runtime
845	  }
846	}
847	
848	template <typename Tuple, std::size_t... Is>
849	constexpr std::size_t sum_targets_impl(std::index_sequence<Is...>) {
850	  return (count_qubits_compile_time<std::tuple_element_t<Is, Tuple>>() + ...);
851	}
852	
853	// Type trait to check if T has a static constexpr integer 'num_parameters'
854	template <typename T, typename = void>
855	struct has_num_parameters : std::false_type {};
856	
857	template <typename T>
858	struct has_num_parameters<T, std::void_t<decltype(T::num_parameters)>>
859	    : std::bool_constant<std::is_integral_v<decltype(T::num_parameters)>> {};
860	
861	template <typename T>
862	inline constexpr bool has_num_parameters_v = has_num_parameters<T>::value;
863	
864	/// @brief Generic quantum operation applicator function. Supports the
865	/// following signatures for a generic operation name `OP`
866	/// `OP(qubit(s))`
867	/// `OP<ctrl>(qubit..., qubit)`
868	/// `OP<ctrl>(qubits, qubit)`
869	/// `OP(scalar..., qubit(s))`
870	/// `OP<ctrl>(scalar..., qubit..., qubit)`
871	/// `OP<ctrl>(scalar..., qubits, qubit)`
872	/// `OP<adj>(qubit)`
873	/// `OP<adj>(scalar..., qubit)`
874	/// Control qubits can be negated. Compile errors should be thrown
875	/// for erroneous signatures.
876	template <typename mod, std::size_t NumT, std::size_t NumP,
877	          typename... RotationT, typename... QuantumT,
878	          std::size_t NumPProvided = sizeof...(RotationT),
879	          std::enable_if_t<NumP == NumPProvided, std::size_t> = 0>
880	void applyQuantumOperation(const std::string &gateName,
881	                           const std::tuple<RotationT...> &paramTuple,
882	                           const std::tuple<QuantumT...> &quantumTuple) {
883	
884	  std::vector<double> parameters;
885	  cudaq::tuple_for_each(paramTuple,
886	                        [&](auto &&element) { parameters.push_back(element); });
887	
888	  std::vector<QuditInfo> qubits;
889	  qubitsToQuditInfos(quantumTuple, qubits);
890	
891	  std::vector<bool> qubitIsNegated;
892	  findQubitNegations(quantumTuple, qubitIsNegated);
893	
894	  assert(qubitIsNegated.size() == qubits.size() && "qubit mismatch");
895	
896	  // Catch the case where we have multi-target broadcast, we don't allow that
897	  if (std::is_same_v<mod, base> && NumT > 1 && qubits.size() > NumT)
898	    throw std::runtime_error(
899	        "cudaq does not support broadcast for multi-qubit operations.");
900	
901	  // Operation on correct number of targets, no controls, possible broadcast
902	  if ((std::is_same_v<mod, base> || std::is_same_v<mod, adj>) && NumT == 1) {
903	    for (auto &qubit : qubits)
904	      getExecutionManager()->apply(gateName, parameters, {}, {qubit},
905	                                   std::is_same_v<mod, adj>);
906	    return;
907	  }
908	
909	  // Partition out the controls and targets
910	  std::size_t numControls = qubits.size() - NumT;
911	  std::vector<QuditInfo> targets(qubits.begin() + numControls, qubits.end()),
912	      controls(qubits.begin(), qubits.begin() + numControls);
913	
914	  // Apply X for any negations
915	  for (std::size_t i = 0; i < controls.size(); i++)
916	    if (qubitIsNegated[i])
917	      getExecutionManager()->apply("x", {}, {}, {controls[i]});
918	
919	  // Apply the gate
920	  getExecutionManager()->apply(gateName, parameters, controls, targets,
921	                               std::is_same_v<mod, adj>);
922	
923	  // Reverse any negations
924	  for (std::size_t i = 0; i < controls.size(); i++)
925	    if (qubitIsNegated[i])
926	      getExecutionManager()->apply("x", {}, {}, {controls[i]});
927	
928	  // Reset the negations
929	  cudaq::tuple_for_each(quantumTuple, [&](auto &&element) {
930	    using T = decltype(element);
931	    if constexpr (IsQubitType<T>::value) {
932	      if (element.is_negative())
933	        element.negate();
934	    } else if constexpr (IsQvectorType<T>::value || IsQviewType<T>::value ||
935	                         IsQarrayType<T>::value) {
936	      for (auto &q : element)
937	        if (q.is_negative())
938	          q.negate();
939	    }
940	  });
941	}
942	
943	template <typename mod, std::size_t NUMT, std::size_t NUMP, typename... Args>
944	void genericApplicator(const std::string &gateName, Args &&...args) {
945	  applyQuantumOperation<mod, NUMT, NUMP>(
946	      gateName, tuple_slice<NUMP>(std::forward_as_tuple(args...)),
947	      tuple_slice_last<sizeof...(Args) - NUMP>(std::forward_as_tuple(args...)));
948	}
949	
950	} // namespace cudaq::detail
951	
952	#define __qop__ __attribute__((annotate("user_custom_quantum_operation")))
953	
954	/// Register a new custom unitary operation providing a unique name,
955	/// the number of target qubits, the number of rotation parameters (can be 0),
956	/// and the unitary matrix as a 1D row-major `std::vector<complex>`
957	/// representation following a MSB qubit ordering.
958	#define CUDAQ_REGISTER_OPERATION(NAME, NUMT, NUMP, ...)                        \
959	  namespace cudaq {                                                            \
960	  struct CONCAT(NAME, _operation) : public ::cudaq::unitary_operation {        \
961	    std::vector<std::complex<double>>                                          \
962	    unitary(const std::vector<double> &parameters) const override {            \
963	      [[maybe_unused]] std::complex<double> i(0, 1.);                          \
964	      return __VA_ARGS__;                                                      \
965	    }                                                                          \
966	    static inline const bool registered_ = []() {                              \
967	      cudaq::customOpRegistry::getInstance()                                   \
968	          .registerOperation<CONCAT(NAME, _operation)>(#NAME);                 \
969	      return true;                                                             \
970	    }();                                                                       \
971	  };                                                                           \
972	  CUDAQ_MOD_TEMPLATE                                                           \
973	  void NAME(Args &&...args) {                                                  \
974	    /* Perform registration at call site as well in case the static            \
975	     * initialization was not executed in the same context, e.g., remote       \
976	     * execution.*/                                                            \
977	    cudaq::customOpRegistry::getInstance()                                     \
978	        .registerOperation<CONCAT(NAME, _operation)>(#NAME);                   \
979	    detail::genericApplicator<mod, NUMT, NUMP>(#NAME,                          \
980	                                               std::forward<Args>(args)...);   \
981	  }                                                                            \
982	  }                                                                            \
983	  __qop__ std::vector<std::complex<double>> CONCAT(NAME,                       \
984	                                                   CONCAT(_generator_, NUMT))( \
985	      const std::vector<double> &parameters = std::vector<double>()) {         \
986	    return __VA_ARGS__;                                                        \
987	  }
